import json, re, pandas as pd

# Load citing-side rows where citation mentions UNIV CALIFORNIA
path = var_call_hYdBVPZoafj93rSXpf5sW6zR
with open(path, 'r', encoding='utf-8') as f:
    citing_recs = json.load(f)

def extract_assignee(patents_info: str):
    if not patents_info:
        return None
    m = re.search(r'is (?:owned by|assigned to|belonging to)\s+(.+?)\s+(?:and has|with pub\.|and has publication|and has pub\.|and has publication no\.)', patents_info)
    if m:
        return m.group(1).strip(' .')
    m = re.search(r'^(.+?)\s+holds\s+the\s+', patents_info)
    if m:
        return m.group(1).strip(' .')
    return None

subclass_pat = re.compile(r'^([A-Z]\d{2}[A-Z])')
rows=[]
for r in citing_recs:
    assignee = extract_assignee(r.get('Patents_info',''))
    if not assignee:
        continue
    if assignee.strip().upper()=='UNIV CALIFORNIA':
        continue
    cpc_raw = r.get('cpc')
    if not cpc_raw:
        continue
    try:
        cpcs=json.loads(cpc_raw)
    except Exception:
        cpcs=[]
    for c in cpcs:
        if c.get('first') is True and c.get('code'):
            m=subclass_pat.match(c['code'])
            if m:
                rows.append({'citing_assignee':assignee, 'subclass':m.group(1)})

df=pd.DataFrame(rows).drop_duplicates()
subclasses=sorted(df['subclass'].unique().tolist())

print('__RESULT__:')
print(json.dumps({'pairs': df.to_dict(orient='records'), 'subclasses': subclasses, 'n_pairs': int(len(df)), 'n_subclasses': int(len(subclasses))}))

